      if (log.message === "Waitpoint created" && log.properties) {
        tokenId = log.properties.tokenId as string;
        break;
      }
    }
    if (tokenId) break;
  }

  console.log(`Token ID: ${tokenId}`);
}

main().catch(console.error);

